DROP TABLE IF EXISTS `materials`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `materials` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `plant` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `material_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `material_description` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `material_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `material_group` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `base_uom` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'PCS',
  `price` decimal(15,2) NOT NULL DEFAULT '0.00',
  `purchase_unit` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `currency` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'IDR',
  `moq` decimal(15,2) DEFAULT NULL,
  `cn` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `maker` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `add_cost_import_tax` decimal(5,2) DEFAULT NULL,
  `price_update` date DEFAULT NULL,
  `price_before` decimal(15,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=24347 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

